// Ukuran maksimum buffer layer: 32
int mlp_predict(double* input_features) {
    double a[32] = {0};
    double b[32] = {0};
    for(int i=0; i<6; i++) a[i] = input_features[i];

    // --- Layer 1 ---
    for(int out=0; out<32; out++) {
        double sum = B_0[out];
        for(int in=0; in<6; in++) {
            sum += a[in] * W_0[in][out];
        }
        b[out] = (sum > 0) ? sum : 0; // ReLU
    }
    for(int i=0; i<32; i++) a[i] = b[i];

    // --- Layer 2 ---
    for(int out=0; out<16; out++) {
        double sum = B_1[out];
        for(int in=0; in<32; in++) {
            sum += a[in] * W_1[in][out];
        }
        b[out] = (sum > 0) ? sum : 0; // ReLU
    }
    for(int i=0; i<16; i++) a[i] = b[i];

    // --- Layer 3 ---
    for(int out=0; out<6; out++) {
        double sum = B_2[out];
        for(int in=0; in<16; in++) {
            sum += a[in] * W_2[in][out];
        }
        b[out] = sum;
    }

    // ArgMax layer terakhir
    int best_class = 0;
    double max_val = b[0];
    for(int i=1; i<6; i++) {
        if(b[i] > max_val) {
            max_val = b[i];
            best_class = i;
        }
    }
    return best_class;
}


